var maximumProfit = function(duration, deadline, profit) {
    const n = duration.length;
    const total = 1 << n;
    const dpProfit = new Array(total).fill(0);
    const dpTime = new Array(total).fill(0);

    for (let mask = 1; mask < total; mask++) {
        let bestProfit = 0, bestTime = 0;
        for (let j = 0; j < n; j++) {
            if (!((mask >> j) & 1)) continue;
            const prevMask = mask ^ (1 << j);
            const finish = dpTime[prevMask] + duration[j];
            const gain = (finish <= deadline[j]) ? profit[j] : 0;
            const candProfit = dpProfit[prevMask] + gain;
            const candTime = finish;
