#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int maximumProfit(int* duration, int* deadline, int* profit, int n) {
    int total = 1 << n;
    int* dpProfit = (int*)malloc(total * sizeof(int));
    int* dpTime = (int*)malloc(total * sizeof(int));
    memset(dpProfit, 0, total * sizeof(int));
    memset(dpTime, 0, total * sizeof(int));

    for (int mask = 1; mask < total; mask++) {
        int bestProfit = 0, bestTime = 0;
        for (int j = 0; j < n; j++) {
            if (!((mask >> j) & 1)) continue;
            int prevMask = mask ^ (1 << j);
            int finish = dpTime[prevMask] + duration[j];
            // 超过截止时间则该任务收益为 0
            int gain = (finish <= deadline[j]) ? profit[j] : 0;
            int candProfit = dpProfit[prevMask] + gain;
            int candTime = finish;
            // 收益更大优先；收益相同时保留更小完成时刻
            if (candProfit > bestProfit ||
                (candProfit == bestProfit && candTime < bestTime)) {
                bestProfit = candProfit;
                bestTime = candTime;
            }
        }
        dpProfit[mask] = bestProfit;
        dpTime[mask] = bestTime;
    }

    int ans = dpProfit[total - 1];
    free(dpProfit);
    free(dpTime);
    return ans;
}
